def gen(rng, size):
    n = max(1, min(size, 20000))
    out = []
    while len(out) < n:
        w = rng.randrange(1, 5)
        if len(out) + w > n:
            break
        if w == 1:
            out.append(rng.randrange(0, 128))
        else:
            lead_ones = (0xFF << (8 - w)) & 0xFF
            lead = lead_ones | rng.randrange(0, 1 << (7 - w))
            out.append(lead)
            for _ in range(w - 1):
                out.append(0x80 | rng.randrange(0, 64))
    if not out:
        out = [0]
    return [out]

