class Solution:
    def validUtf8(self, data):
        i = 0
        n = len(data)
        while i < n:
            b = data[i] & 0xFF
            bits = format(b, '08b')
            if bits[0] == '0':
                width = 1
            elif bits[:3] == '110':
                width = 2
            elif bits[:4] == '1110':
                width = 3
            elif bits[:5] == '11110':
                width = 4
            else:
                return False
            if i + width > n:
                return False
            for j in range(1, width):
                cb = data[i + j] & 0xFF
                if format(cb, '08b')[:2] != '10':
                    return False
            i += width
        return True

