class Solution:
    def validUtf8(self, data):
        remaining = 0
        for num in data:
            b = num & 0xFF
            if remaining == 0:
                if b >> 7 == 0:
                    remaining = 0
                elif b >> 5 == 0b110:
                    remaining = 1
                elif b >> 4 == 0b1110:
                    remaining = 2
                elif b >> 3 == 0b11110:
                    remaining = 3
                else:
                    return False
            else:
                if b >> 6 != 0b10:
                    return False
                remaining -= 1
        return remaining == 0

