var validUtf8 = function(data) {
    let remaining = 0;
    for (let num of data) {
        const b = num & 0xFF;
        if (remaining === 0) {
            if (b >> 7 === 0) remaining = 0;
            else if (b >> 5 === 0b110) remaining = 1;
            else if (b >> 4 === 0b1110) remaining = 2;
            else if (b >> 3 === 0b11110) remaining = 3;
            else return false;
        } else {
            if (b >> 6 !== 0b10) return false;
            remaining -= 1;
        }
    }
    return remaining === 0;
};
